from fastapi import APIRouter, Depends, UploadFile, File, HTTPExceptionfrom sqlalchemy.orm import Sessionfrom database import get_dbfrom models import LibraryImagefrom PIL import Imageimport numpy as npimport aiofilesimport uuidimport osrouter = APIRouter()UPLOAD_DIR = "uploads"def preprocess_image(image: Image.Image) -> Image.Image:    # convert to RGBA to handle transparency    image = image.convert("RGBA")    data = np.array(image)    r, g, b, a = data[:,:,0], data[:,:,1], data[:,:,2], data[:,:,3]    non_white = ~((r > 240) & (g > 240) & (b > 240)) & (a > 10)    rows = np.any(non_white, axis=1)    cols = np.any(non_white, axis=0)    if not rows.any():        # fully transparent or white image        square = Image.new("RGB", (500, 500), (255, 255, 255))        return square    top, bottom = np.where(rows)[0][[0, -1]]    left, right = np.where(cols)[0][[0, -1]]    padding = 10    top    = max(0, top - padding)    bottom = min(data.shape[0], bottom + padding)    left   = max(0, left - padding)    right  = min(data.shape[1], right + padding)    image = image.crop((left, top, right, bottom))    # create white background and composite RGBA image onto it    # this correctly fills transparent areas with white instead of black    w, h = image.size    size = max(w, h)    square = Image.new("RGB", (size, size), (255, 255, 255))    offset = ((size - w) // 2, (size - h) // 2)    # paste using the alpha channel as mask so transparency becomes white    square.paste(image, offset, mask=image.split()[3])    return square@router.get("/")def get_library(db: Session = Depends(get_db)):    images = db.query(LibraryImage).order_by(LibraryImage.created_at.desc()).all()    return images@router.post("/")async def upload_image(file: UploadFile = File(...), db: Session = Depends(get_db)):    if file.content_type not in ["image/jpeg", "image/png", "image/webp"]:        raise HTTPException(status_code=400, detail="Only JPEG, PNG, and WEBP images are accepted")    contents = await file.read()    from io import BytesIO    image = Image.open(BytesIO(contents))    processed = preprocess_image(image)    filename = f"{uuid.uuid4()}.jpg"    filepath = os.path.join(UPLOAD_DIR, filename)    processed.save(filepath, "JPEG", quality=90)    url = f"/uploads/{filename}"    db_image = LibraryImage(        id=str(uuid.uuid4()),        url=url,        name=file.filename,    )    db.add(db_image)    db.commit()    db.refresh(db_image)    return db_image@router.delete("/{image_id}")def delete_image(image_id: str, db: Session = Depends(get_db)):    image = db.query(LibraryImage).filter(LibraryImage.id == image_id).first()    if not image:        raise HTTPException(status_code=404, detail="Image not found")    filepath = image.url.lstrip("/")    if os.path.exists(filepath):        os.remove(filepath)    db.delete(image)    db.commit()    return {"ok": True}